import{_ as e,o as a,c as o,ag as r,ah as d}from"./chunks/framework.D9bIGSBm.js";const m=JSON.parse('{"title":"斜杠命令与文件面板","description":"","frontmatter":{},"headers":[],"relativePath":"features/slash-commands.md","filePath":"features/slash-commands.md"}'),l={name:"features/slash-commands.md"};function i(c,t,s,n,h,p){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="斜杠命令与文件面板" tabindex="-1">斜杠命令与文件面板 <a class="header-anchor" href="#斜杠命令与文件面板" aria-label="Permalink to &quot;斜杠命令与文件面板&quot;">​</a></h1><p>输入框有三种快捷触发方式，帮助你快速插入命令、引用文件。本页逐一介绍它们的用法与细节。</p><blockquote><p>相关基础：<a href="/docs/guide/interface-overview.html">界面导览</a>、<a href="/docs/guide/quick-start.html">快速上手</a></p></blockquote><hr><h2 id="输入框触发提示" tabindex="-1">输入框触发提示 <a class="header-anchor" href="#输入框触发提示" aria-label="Permalink to &quot;输入框触发提示&quot;">​</a></h2><p>当光标停在任务草稿输入框时，占位提示会显示三种触发方式：</p><blockquote><p>「向 Claude 提问，输入 @ 添加文件，/ 使用命令，$ 使用技能」</p></blockquote><ul><li>输入 <code>/</code> —— 打开<strong>命令面板</strong>，浏览并调用斜杠命令或技能</li><li>输入 <code>@</code> —— 打开<strong>文件面板</strong>，将工作区文件附加到消息</li><li>输入 <code>$</code> —— 快速筛选出技能类命令（技能本质上也是斜杠命令的一种，在命令面板中以技能徽标区分）</li></ul><hr><h2 id="命令面板" tabindex="-1">/ 命令面板 <a class="header-anchor" href="#命令面板" aria-label="Permalink to &quot;/ 命令面板&quot;">​</a></h2><h3 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h3><p>命令面板（Command Palette）是所有<strong>斜杠命令</strong>的统一入口。你可以在这里搜索并选用来自不同来源的命令，包括内置功能命令、你自己定义的用户命令、项目级命令、插件提供的命令，以及各种技能（Skill）。</p><p>技能是一类特殊的可调用单元，与普通命令共享同一个面板，通过徽标区分。</p><h3 id="在哪里打开" tabindex="-1">在哪里打开 <a class="header-anchor" href="#在哪里打开" aria-label="Permalink to &quot;在哪里打开&quot;">​</a></h3><p>在输入框中，光标所在文本段以 <code>/</code> 开头、且不含空格或换行时，命令面板自动弹出在输入框上方。</p><h3 id="怎么用" tabindex="-1">怎么用 <a class="header-anchor" href="#怎么用" aria-label="Permalink to &quot;怎么用&quot;">​</a></h3><ol><li>在输入框中输入 <code>/</code>，命令面板立即弹出，显示全部可用命令。</li><li>继续输入关键词过滤（例如 <code>/compact</code>），列表实时缩小。 <ul><li>对于 <code>plugin:cmd-name</code> 格式的插件命令，输入冒号后的部分也能匹配（例如 <code>/bra</code> 可以匹配 <code>/superpowers:brainstorming</code>）。</li></ul></li><li>用方向键 ↑↓ 上下导航，或直接用鼠标悬停高亮。</li><li>按 <strong>Enter</strong> 或 <strong>Tab</strong> 确认选中，也可点击某条命令。</li><li>选中后，<code>/query</code> 文本自动替换为该命令的标签片段，插入到光标位置。</li><li>按 <strong>Esc</strong> 关闭面板（再次输入 <code>/</code> 可重新打开）。</li></ol><p>无匹配时面板提示「没有匹配的命令」。</p><p><strong>示例</strong>：输入 <code>/compact</code> → 选中 compact 命令 → 按 Enter，输入框出现该命令标签，发送后 AI 将压缩当前对话历史。</p><p><img src="'+d+'" alt="截图：命令面板弹出在输入框上方，列表中显示多条命令，每条右侧有来源徽标与类型徽标，当前高亮第一条"></p><h3 id="命令来源徽标" tabindex="-1">命令来源徽标 <a class="header-anchor" href="#命令来源徽标" aria-label="Permalink to &quot;命令来源徽标&quot;">​</a></h3><p>每条命令右侧显示两枚彩色徽标，分别标注该命令的<strong>来源</strong>和<strong>类型</strong>。</p><p><strong>来源徽标</strong>（第一枚）：</p><table tabindex="0"><thead><tr><th>徽标显示</th><th>颜色</th><th>含义</th></tr></thead><tbody><tr><td>user</td><td>蓝色</td><td>用户个人自定义命令</td></tr><tr><td>project</td><td>绿色</td><td>当前项目级命令（存放于项目内）</td></tr><tr><td>plugin</td><td>紫色</td><td>插件提供的命令</td></tr><tr><td>内置</td><td>灰色</td><td>应用内置命令</td></tr></tbody></table><p><strong>类型徽标</strong>（第二枚）：</p><table tabindex="0"><thead><tr><th>徽标显示</th><th>颜色</th><th>含义</th></tr></thead><tbody><tr><td>command</td><td>无背景（浅灰文字）</td><td>普通命令</td></tr><tr><td>skill</td><td>琥珀色</td><td>技能（Skill），可调用专项能力</td></tr><tr><td>workflow</td><td>玫红色</td><td>工作流</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">0.5.2 起支持双徽标</p><p>v0.5.2 起，命令面板每条目同时展示来源与类型两枚徽标，方便你在命令较多时快速定位来源。技能命令的来源徽标会根据是否属于插件自动推导：插件技能显示 <strong>plugin</strong>（紫色），用户技能显示 <strong>user</strong>（蓝色）。</p></div><hr><h2 id="文件面板" tabindex="-1">@ 文件面板 <a class="header-anchor" href="#文件面板" aria-label="Permalink to &quot;@ 文件面板&quot;">​</a></h2><h3 id="这是什么-1" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么-1" aria-label="Permalink to &quot;这是什么&quot;">​</a></h3><p>文件面板（File Palette）让你快速在消息里引用工作区文件，AI 会将被引用文件的内容作为上下文处理。</p><h3 id="在哪里打开-1" tabindex="-1">在哪里打开 <a class="header-anchor" href="#在哪里打开-1" aria-label="Permalink to &quot;在哪里打开&quot;">​</a></h3><p>在输入框任意位置输入 <code>@</code>，且 <code>@</code> 前面是行首或空格（非词中间），文件面板自动弹出。光标与 <code>@</code> 之间不能有空格，否则面板不会触发。</p><h3 id="怎么用-1" tabindex="-1">怎么用 <a class="header-anchor" href="#怎么用-1" aria-label="Permalink to &quot;怎么用&quot;">​</a></h3><ol><li>在输入框中输入 <code>@</code>，文件面板弹出，显示工作区所有可索引文件。</li><li>继续输入文件名关键词（例如 <code>@README</code>），列表按相关度排序过滤：完全匹配 &gt; 文件名前缀 &gt; 路径前缀 &gt; 文件名包含 &gt; 路径包含。</li><li>用方向键 ↑↓ 或鼠标选中目标文件，按 <strong>Enter</strong> 或点击确认。</li><li>选中后 <code>@query</code> 被替换为文件标签片段（显示文件名）；图片文件会直接转为图片片段嵌入消息。</li><li>最多显示 50 条匹配结果，超出时提示「还有 {n} 条…」。</li></ol><p><strong>示例</strong>：输入 <code>@src/main</code> → 面板过滤出以 <code>src/main</code> 开头的文件 → 选中 <code>src/main.ts</code> → Enter，消息里出现该文件标签。</p><div class="tip custom-block"><p class="custom-block-title">找不到文件？</p><p>文件面板仅显示工作区<strong>已索引</strong>文件。若文件未出现，请确认已打开对应工作区（左侧栏「查看文件」），或文件是否在 .gitignore 等忽略范围内。</p></div><hr><h2 id="技能触发" tabindex="-1">$ 技能触发 <a class="header-anchor" href="#技能触发" aria-label="Permalink to &quot;$ 技能触发&quot;">​</a></h2><p>技能（Skill）是通过命令面板调用的专项能力单元，在面板中以琥珀色 <strong>skill</strong> 徽标标注。</p><p>使用方式：</p><ul><li>直接输入 <code>/</code> 打开命令面板，再输入技能名称关键词筛选；</li><li>或输入 <code>$</code> 后跟技能名作为快捷搜索前缀（<code>$</code> 为触发提示，最终仍通过命令面板完成选择）。</li></ul><p>选中技能命令后，AI 会调用对应技能执行专项任务。</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>了解输入触发方式之后，可以进一步探索对话历史的代码快照与回滚功能，前往<a href="/docs/features/checkpoints.html">代码检查点</a>继续学习。</p>',46)])])}const g=e(l,[["render",i]]);export{m as __pageData,g as default};
